CREATE TABLE IF NOT EXISTS usuarios (id SERIAL PRIMARY KEY,nome VARCHAR(120) UNIQUE NOT NULL,senha_hash VARCHAR(255) NOT NULL,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS correcoes_n2 (id SERIAL PRIMARY KEY,titulo VARCHAR(255) NOT NULL,sistema VARCHAR(150),categoria VARCHAR(120),criticidade VARCHAR(20) DEFAULT 'Baixa',erro TEXT,causa TEXT,correcao TEXT,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS anexos_correcoes (id SERIAL PRIMARY KEY,correcao_id INTEGER NOT NULL REFERENCES correcoes_n2(id),nome_arquivo VARCHAR(255) NOT NULL,mime_type VARCHAR(100) NOT NULL,conteudo BYTEA NOT NULL,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS scripts_sql (id SERIAL PRIMARY KEY,titulo VARCHAR(255) NOT NULL,tipo_banco VARCHAR(80) NOT NULL,descricao TEXT,observacoes TEXT,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS consultas_sql (id SERIAL PRIMARY KEY,script_id INTEGER NOT NULL REFERENCES scripts_sql(id),titulo_consulta VARCHAR(255) NOT NULL,codigo_sql TEXT NOT NULL,ordem INTEGER DEFAULT 0,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS bancos_mapeados (id SERIAL PRIMARY KEY,nome VARCHAR(180) NOT NULL,tipo_banco VARCHAR(80),descricao TEXT,observacoes TEXT,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS arquivos_download (id SERIAL PRIMARY KEY,modulo VARCHAR(30) NOT NULL,nome VARCHAR(255) NOT NULL,tipo VARCHAR(30) NOT NULL,caminho VARCHAR(500),conteudo BYTEA,mime_type VARCHAR(120),downloads INTEGER DEFAULT 0,created_at TIMESTAMP NOT NULL DEFAULT NOW(),updated_at TIMESTAMP NOT NULL DEFAULT NOW(),deleted_at TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_correcoes_ativas ON correcoes_n2(deleted_at);
CREATE INDEX IF NOT EXISTS idx_scripts_ativos ON scripts_sql(deleted_at);
CREATE INDEX IF NOT EXISTS idx_arquivos_modulo ON arquivos_download(modulo, deleted_at);
